import { describe, it, expect, beforeEach, vi } from 'vitest'

// We test that the axios instance exported from @/api/axios.ts:
// 1. Has baseURL set to '/api'
// 2. Has a request interceptor that adds Authorization Bearer token from localStorage

describe('axios instance', () => {
  beforeEach(() => {
    localStorage.clear()
  })

  it('should have baseURL set to /api', async () => {
    const { default: api } = await import('@/api/axios')
    expect(api.defaults.baseURL).toBe('/api')
  })

  it('should add Authorization header when token exists in localStorage', async () => {
    localStorage.setItem('token', 'test-jwt-token')

    // Re-import to get fresh instance
    const { default: api } = await import('@/api/axios')

    // Simulate interceptor by running the request config through interceptors
    // We create a mock config and run interceptors manually
    const config = { headers: {} } as any
    const interceptor = (api.interceptors.request as any).handlers[0]
    expect(interceptor).toBeDefined()

    const result = interceptor.fulfilled(config)
    expect(result.headers['Authorization']).toBe('Bearer test-jwt-token')
  })

  it('should NOT add Authorization header when no token in localStorage', async () => {
    const { default: api } = await import('@/api/axios')

    const config = { headers: {} } as any
    const interceptor = (api.interceptors.request as any).handlers[0]
    expect(interceptor).toBeDefined()

    const result = interceptor.fulfilled(config)
    expect(result.headers['Authorization']).toBeUndefined()
  })
})

