import api from '@/api/axios'
import { login, register, getMe } from '@/api/auth'

describe('auth API', () => {
  beforeEach(() => {
    vi.clearAllMocks()
    localStorage.clear()
  })

  describe('login', () => {
    it('should POST to /auth/login with username and password', async () => {
      const mockResponse = { data: { token: 'jwt-token', expiresIn: 86400 } }
      vi.mocked(api.post).mockResolvedValue(mockResponse)

      await login('testuser', 'password123')

      expect(api.post).toHaveBeenCalledWith('/auth/login', {
        username: 'testuser',
        password: 'password123',
      })
    })

    it('should store token in localStorage on successful login', async () => {
      const mockResponse = { data: { token: 'jwt-token-abc', expiresIn: 86400 } }
      vi.mocked(api.post).mockResolvedValue(mockResponse)

      await login('testuser', 'password123')

      expect(localStorage.getItem('token')).toBe('jwt-token-abc')
    })

    it('should return the response data', async () => {
      const mockData = { token: 'jwt-token', expiresIn: 86400 }
      vi.mocked(api.post).mockResolvedValue({ data: mockData })

      const result = await login('testuser', 'password123')

      expect(result).toEqual(mockData)
    })
  })

  describe('register', () => {
    it('should POST to /auth/register with username, password, and displayName', async () => {
      const mockResponse = { data: { id: 1, username: 'newuser', displayName: 'New User' } }
      vi.mocked(api.post).mockResolvedValue(mockResponse)

      await register('newuser', 'password123', 'New User')

      expect(api.post).toHaveBeenCalledWith('/auth/register', {
        username: 'newuser',
        password: 'password123',
        displayName: 'New User',
      })
    })

    it('should return the response data', async () => {
      const mockData = { id: 1, username: 'newuser', displayName: 'New User' }
      vi.mocked(api.post).mockResolvedValue({ data: mockData })

      const result = await register('newuser', 'password123', 'New User')

      expect(result).toEqual(mockData)
    })
  })

  describe('getMe', () => {
    it('should GET /auth/me', async () => {
      const mockResponse = { data: { id: 1, username: 'testuser', displayName: 'Test' } }
      vi.mocked(api.get).mockResolvedValue(mockResponse)

      await getMe()

      expect(api.get).toHaveBeenCalledWith('/auth/me')
    })

    it('should return the response data', async () => {
      const mockData = { id: 1, username: 'testuser', displayName: 'Test' }
      vi.mocked(api.get).mockResolvedValue({ data: mockData })

      const result = await getMe()

      expect(result).toEqual(mockData)
    })
  })
})

