import { useTaskStore } from '@/stores/taskStore'
import { fetchTasks as apiFetchTasks, createTask as apiCreateTask } from '@/api/tasks'

describe('taskStore', () => {
  beforeEach(() => {
    setActivePinia(createPinia())
    vi.clearAllMocks()
  })

  describe('initial state', () => {
    it('should have correct default state', () => {
      const store = useTaskStore()

      expect(store.tasks).toEqual([])
      expect(store.page).toBe(0)
      expect(store.size).toBe(20)
      expect(store.totalElements).toBe(0)
      expect(store.totalPages).toBe(0)
      expect(store.keyword).toBe('')
      expect(store.priorityFilter).toBeNull()
      expect(store.statusFilter).toBeNull()
      expect(store.loading).toBe(false)
      expect(store.error).toBeNull()
    })
  })

  describe('fetchTasks action', () => {
    it('should call API with current state params and update tasks', async () => {
      const mockPageData = {
        content: [
          { id: 1, title: 'Task 1', status: 'TODO', priority: 'HIGH' },
          { id: 2, title: 'Task 2', status: 'IN_PROGRESS', priority: 'LOW' },
        ],
        page: 0,
        size: 20,
        totalElements: 2,
        totalPages: 1,
      }
      vi.mocked(apiFetchTasks).mockResolvedValue(mockPageData)

      const store = useTaskStore()
      await store.fetchTasks()

      expect(apiFetchTasks).toHaveBeenCalledWith({
        page: 0,
        size: 20,
        keyword: '',
        priority: null,
        status: null,
      })
      expect(store.tasks).toEqual(mockPageData.content)
      expect(store.totalElements).toBe(2)
      expect(store.totalPages).toBe(1)
    })

    it('should set loading to true while fetching and false after', async () => {
      vi.mocked(apiFetchTasks).mockImplementation(() => {
        return new Promise((resolve) => {
          setTimeout(() => {
            resolve({
              content: [],
              page: 0,
              size: 20,
              totalElements: 0,
              totalPages: 0,
            })
          }, 10)
        })
      })

      const store = useTaskStore()
      const fetchPromise = store.fetchTasks()

      expect(store.loading).toBe(true)

      await fetchPromise

      expect(store.loading).toBe(false)
    })

    it('should set error state on API failure', async () => {
      vi.mocked(apiFetchTasks).mockRejectedValue(new Error('Network error'))

      const store = useTaskStore()
      await store.fetchTasks()

      expect(store.error).toBeTruthy()
      expect(store.loading).toBe(false)
    })

    it('should pass filters to API when set', async () => {
      const mockPageData = {
        content: [],
        page: 0,
        size: 20,
        totalElements: 0,
        totalPages: 0,
      }
      vi.mocked(apiFetchTasks).mockResolvedValue(mockPageData)

      const store = useTaskStore()
      store.keyword = 'search term'
      store.priorityFilter = 'HIGH'
      store.statusFilter = 'TODO'
      store.page = 2

      await store.fetchTasks()

      expect(apiFetchTasks).toHaveBeenCalledWith({
        page: 2,
        size: 20,
        keyword: 'search term',
        priority: 'HIGH',
        status: 'TODO',
      })
    })
  })

  describe('filter actions', () => {
    it('setKeyword should update keyword and reset page to 0', () => {
      const store = useTaskStore()
      store.page = 3

      store.setKeyword('new keyword')

      expect(store.keyword).toBe('new keyword')
      expect(store.page).toBe(0)
    })

    it('setPriorityFilter should update priorityFilter and reset page to 0', () => {
      const store = useTaskStore()
      store.page = 5

      store.setPriorityFilter('LOW')

      expect(store.priorityFilter).toBe('LOW')
      expect(store.page).toBe(0)
    })

    it('setStatusFilter should update statusFilter and reset page to 0', () => {
      const store = useTaskStore()
      store.page = 2

      store.setStatusFilter('DONE')

      expect(store.statusFilter).toBe('DONE')
      expect(store.page).toBe(0)
    })

    it('setPage should update the page number', () => {
      const store = useTaskStore()

      store.setPage(4)

      expect(store.page).toBe(4)
    })
  })

  describe('createTask action', () => {
    it('should call createTask API and then refresh tasks list', async () => {
      const newTask = { title: 'New Task', priority: 'MEDIUM' as const }
      const createdTask = { id: 1, ...newTask, status: 'TODO' }

      vi.mocked(apiCreateTask).mockResolvedValue(createdTask)
      vi.mocked(apiFetchTasks).mockResolvedValue({
        content: [createdTask],
        page: 0,
        size: 20,
        totalElements: 1,
        totalPages: 1,
      })

      const store = useTaskStore()
      await store.createTask(newTask)

      expect(apiCreateTask).toHaveBeenCalledWith(newTask)
      expect(apiFetchTasks).toHaveBeenCalled()
    })
  })
})

import { describe, it, expect } from 'vitest'
import router from '@/router/index'

describe('router configuration', () => {
  it('should have a /tasks route', () => {
    const routes = router.getRoutes()
    const tasksRoute = routes.find((r) => r.path === '/tasks')

    expect(tasksRoute).toBeDefined()
  })

  it('should have /tasks route with name "tasks"', () => {
    const routes = router.getRoutes()
    const tasksRoute = routes.find((r) => r.path === '/tasks')

    expect(tasksRoute?.name).toBe('tasks')
  })

  it('should lazy-load TaskListPage component for /tasks', () => {
    const routes = router.getRoutes()
    const tasksRoute = routes.find((r) => r.path === '/tasks')

    // The component should be a lazy-loaded function (not eagerly imported)
    expect(tasksRoute).toBeDefined()
    // Route components from lazy imports are stored as a function or as matched components
    const routeConfig = router.options.routes.find((r) => r.path === '/tasks')
    expect(routeConfig).toBeDefined()
    expect(typeof routeConfig!.component).toBe('function')
  })

  it('should still have the home route', () => {
    const routes = router.getRoutes()
    const homeRoute = routes.find((r) => r.path === '/')

    expect(homeRoute).toBeDefined()
    expect(homeRoute?.name).toBe('home')
  })
})

